solutions.python:
import sys
import os

class Solution:
    def hasNonNilTail(self, head: list[int]) -> bool:
        if head is None: return False
        while head and head[0] != None:
            head = head[1:]
        return len(head) > 0

if __name__ == '__main__':
    for line in sys.stdin:
        head = list(map(int, line.split()))
        solution = Solution()
        ret = solution.hasNonNilTail(head)
        print('true' if ret else 'false')

