#include <iostream>
#include <vector>

bool hasNonNilTail(std::vector<int>* head) {
    if (head == nullptr) return false;
    while (head->size() > 1) {
        head = std::vector<int>::iterator(head->begin() + 1);
    }
    return head->size() > 0;
}

int main() {
    std::vector<int>* head = nullptr;
    std::cin >> head;
    bool ret = hasNonNilTail(head);
    std::cout << std::boolalpha << ret;
    return 0;
}
